// This constrained decoder strategy alternates between unconstrained and constrained steps.
// Unconstrained steps generate free text until a complete expression is formed, ensuring
// that the final output is a valid first-order logic formula. Constrained steps are used
// within the " << " and " >> " delimiters to maintain grammar compliance.
// The strategy aims to balance free text generation with grammar validation, ensuring
// that the output is both accurate and formatted correctly.
// CSD_RATIONALE_END

generated := [];
var stepCounter := 0; // Track the number of steps taken
while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  if stepCounter % 2 == 0 {
    // Unconstrained step: generate free text
    CSDHelpers.RollbackPreservesTokenInvariant(lm, parser, generated);
    var next, newSteps := helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  } else {
    // Constrained step: ensure grammar compliance within << >> segment
    CSDHelpers.RollbackPreservesTokenInvariant(lm, parser, generated);
    var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  }
  stepCounter := stepCounter + 1;
}

